module ClockGatingCell (
  input clock,
  input enable,
  output gated_clock
);

  reg gated_clock;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clock or posedge dbg_halt) begin
    if (enable) begin
      gated_clock <= clock;
    end else begin
      gated_clock <= 1'b0;
    end
  end

endmodule
